import React, { useEffect, useState } from "react";
import Layout from "../../components/shared/Layout/Layout";
import moment from "moment";
import API from "../../services/API";
import { useSelector } from "react-redux";

const Consumer = () => {
  const { user } = useSelector((state) => state.auth);
  const [data, setData] = useState([]);

  const getRequests = async () => {
    try {
      const { data } = await API.post("/inventory/get-inventory-hospital", {
        filters: { inventoryType: "out", hospital: user?._id },
      });
      if (data?.success) setData(data?.inventory);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getRequests();
  }, []);

  const totalML = data.reduce((sum, r) => sum + (Number(r.quantity) || 0), 0);

  return (
    <Layout>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
        .con-page { font-family: 'DM Sans', sans-serif; }
        .con-title { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 700; color: #fff; margin-bottom: 4px; }
        .con-title span { background: linear-gradient(90deg, #c084fc, #f472b6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
        .con-subtitle { font-size: 14px; color: rgba(255,255,255,0.4); margin-bottom: 28px; }
        .con-info { padding: 16px 20px; border-radius: 14px; margin-bottom: 24px; background: rgba(99,102,241,0.08); border: 1px solid rgba(99,102,241,0.2); font-size: 13px; color: rgba(255,255,255,0.5); line-height: 1.6; }
        .con-info strong { color: rgba(255,255,255,0.8); }
        .con-stats { display: flex; gap: 14px; margin-bottom: 28px; flex-wrap: wrap; }
        .con-stat { flex: 1; min-width: 130px; padding: 18px 20px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); text-align: center; }
        .con-stat-num { font-family: 'Syne', sans-serif; font-size: 28px; font-weight: 800; color: #fff; }
        .con-stat-label { font-size: 12px; color: rgba(255,255,255,0.35); margin-top: 4px; }
        .con-stat.purple { border-color: rgba(168,85,247,0.25); background: rgba(168,85,247,0.07); }
        .con-stat.pink { border-color: rgba(236,72,153,0.25); background: rgba(236,72,153,0.07); }
        .con-stat.blue { border-color: rgba(99,102,241,0.25); background: rgba(99,102,241,0.07); }
        .con-table-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 22px; }
        .con-table-title { font-family: 'Syne', sans-serif; font-size: 15px; font-weight: 700; color: rgba(255,255,255,0.85); margin-bottom: 18px; }
        .con-table { width: 100%; border-collapse: collapse; font-size: 13px; }
        .con-table th { text-align: left; padding: 10px 14px; font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); text-transform: uppercase; letter-spacing: 0.8px; border-bottom: 1px solid rgba(255,255,255,0.06); }
        .con-table td { padding: 14px; color: rgba(255,255,255,0.65); border-bottom: 1px solid rgba(255,255,255,0.04); vertical-align: middle; }
        .con-table tr:last-child td { border-bottom: none; }
        .con-table tr:hover td { background: rgba(168,85,247,0.05); color: rgba(255,255,255,0.9); }
        .con-badge { display: inline-block; padding: 4px 12px; border-radius: 8px; font-size: 11px; font-weight: 600; }
        .con-badge-blood { background: rgba(168,85,247,0.15); color: #c084fc; }
        .con-badge-out { background: rgba(239,68,68,0.12); color: #f87171; }
        .con-empty { text-align: center; padding: 60px 20px; }
        .con-empty-icon { font-size: 48px; margin-bottom: 12px; }
        .con-empty-text { font-size: 15px; color: rgba(255,255,255,0.3); margin-bottom: 6px; }
        .con-empty-sub { font-size: 13px; color: rgba(255,255,255,0.18); }
        .con-req-btn { display: inline-flex; align-items: center; gap: 8px; padding: 11px 22px; border-radius: 12px; border: none; cursor: pointer; background: linear-gradient(135deg, #9333ea, #ec4899); color: white; font-size: 14px; font-weight: 600; font-family: 'DM Sans', sans-serif; box-shadow: 0 4px 16px rgba(147,51,234,0.35); transition: all 0.2s; margin-bottom: 24px; text-decoration: none; }
        .con-req-btn:hover { transform: translateY(-2px); color: white; }
      `}</style>

      <div className="con-page">
        <div className="con-title">
          Blood <span>Requests</span> 💉
        </div>
        <div className="con-subtitle">
          All blood your hospital has requested from organisations
        </div>

        <div className="con-info">
          💡 <strong>How it works:</strong> When your hospital needs blood, go
          to the <strong>Home page</strong> and click{" "}
          <strong>"Request Blood"</strong>. Select the blood group, quantity,
          and which blood bank to request from. All your past requests appear
          here with full details.
        </div>

        <a href="/" className="con-req-btn">
          🩸 Request Blood → Go to Home
        </a>

        <div className="con-stats">
          <div className="con-stat purple">
            <div className="con-stat-num">{data.length}</div>
            <div className="con-stat-label">Total Requests</div>
          </div>
          <div className="con-stat pink">
            <div className="con-stat-num">{totalML}</div>
            <div className="con-stat-label">Total ML Received</div>
          </div>
          <div className="con-stat blue">
            <div className="con-stat-num">
              {[...new Set(data.map((r) => r.bloodGroup))].length}
            </div>
            <div className="con-stat-label">Blood Groups Received</div>
          </div>
        </div>

        <div className="con-table-card">
          <div className="con-table-title">📋 Full Request History</div>
          {data.length === 0 ? (
            <div className="con-empty">
              <div className="con-empty-icon">💉</div>
              <div className="con-empty-text">No blood requests yet</div>
              <div className="con-empty-sub">
                Go to Home page and click "Request Blood" to get started
              </div>
            </div>
          ) : (
            <table className="con-table">
              <thead>
                <tr>
                  <th>Blood Group</th>
                  <th>Type</th>
                  <th>Quantity</th>
                  <th>From Organisation</th>
                  <th>Date & Time</th>
                </tr>
              </thead>
              <tbody>
                {data.map((record) => (
                  <tr key={record._id}>
                    <td>
                      <span className="con-badge con-badge-blood">
                        {record.bloodGroup}
                      </span>
                    </td>
                    <td>
                      <span className="con-badge con-badge-out">Received</span>
                    </td>
                    <td>{record.quantity} ML</td>
                    <td>{record.organisation?.organisationName || "—"}</td>
                    <td>
                      {moment(record.createdAt).format("DD MMM YYYY, hh:mm A")}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </Layout>
  );
};

export default Consumer;
